// ==========================================
// QUOTATION CLIENT SCRIPT
// Source of Truth: LEAD
// Fields:
//   custom_lead        → Link (Lead)
//   custom_survey      → Link (Survey)
//   custom_lead_files_html → HTML
// ==========================================

frappe.ui.form.on("Quotation", {

    refresh(frm) {

        const wrapper = frm.fields_dict.custom_lead_files_html?.$wrapper;
        if (!wrapper) return;

        if (!frm.doc.custom_lead) {
            wrapper.html(`<em style="color:#888;">Please link a Lead first.</em>`);
            return;
        }

        frm.trigger("render_attachments");
    },

    // ----------------------------------
    // Render Lead Attachments
    // ----------------------------------
    render_attachments(frm) {

        const wrapper = frm.fields_dict.custom_lead_files_html.$wrapper;

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "File",
                filters: {
                    attached_to_doctype: "Lead",
                    attached_to_name: frm.doc.custom_lead
                },
                fields: ["file_name", "file_url"],
                order_by: "creation desc",
                limit_page_length: 0
            },
            callback(r) {

                let html = `
                    <div style="margin-bottom:10px;">
                        <button class="btn btn-xs btn-primary upload-quotation-attachment">
                            <i class="fa fa-plus"></i> Add Attachment
                        </button>
                    </div>
                `;

                if (!r.message || !r.message.length) {
                    html += `<em style="color:#888;">No attachments found.</em>`;
                } else {

                    const seen = new Set();

                    r.message.forEach(file => {
                        if (seen.has(file.file_url)) return;
                        seen.add(file.file_url);

                        html += `
                            <div style="margin-bottom:8px; display:flex; align-items:center; gap:8px;
                                        padding:6px; background:#f9f9f9; border-radius:4px;">
                                <i class="fa fa-paperclip" style="color:#5e64ff;"></i>
                                <a href="${file.file_url}" target="_blank" style="flex:1;">
                                    ${file.file_name}
                                </a>
                                <button class="btn btn-xs btn-danger remove-attachment"
                                    data-file-url="${file.file_url}">
                                    <i class="fa fa-trash"></i>
                                </button>
                            </div>
                        `;
                    });
                }

                wrapper.html(html);

                // Upload
                wrapper.find(".upload-quotation-attachment")
                    .off("click")
                    .on("click", () => frm.trigger("upload_attachment"));

                // Remove
                wrapper.off("click", ".remove-attachment");
                wrapper.on("click", ".remove-attachment", function () {
                    frm.trigger("remove_attachment", $(this).data("file-url"));
                });
            }
        });
    },

    // ----------------------------------
    // Upload File (FileUploader already creates File)
    // ----------------------------------
    upload_attachment(frm) {

        new frappe.ui.FileUploader({
            allow_multiple: true,

            on_success(file_doc) {
                // file_doc IS ALREADY a File
                frm.events.sync_attachment_to_all(frm, file_doc);
            }
        });
    },

    // ----------------------------------
    // Sync to Lead + Survey
    // ----------------------------------
    sync_attachment_to_all(frm, file_data) {

        const tasks = [];

        // Lead (source)
        tasks.push(
            frm.events.ensure_file_link(
                "Lead",
                frm.doc.custom_lead,
                file_data
            )
        );

        // Survey (optional)
        if (frm.doc.custom_survey) {
            tasks.push(
                frm.events.ensure_file_link(
                    "Survey",
                    frm.doc.custom_survey,
                    file_data
                )
            );
        }

        Promise.all(tasks).then(() => {
            frappe.show_alert({
                message: "Attachment synced to Lead & Survey",
                indicator: "green"
            });
            frm.trigger("render_attachments");
        });
    },

    // ----------------------------------
    // Ensure File Exists (NO DUPLICATES)
    // ----------------------------------
    ensure_file_link(doctype, docname, file_data) {

        return frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "File",
                filters: {
                    file_url: file_data.file_url,
                    attached_to_doctype: doctype,
                    attached_to_name: docname
                },
                fields: ["name"]
            }
        }).then(r => {

            // Already linked → do nothing
            if (r.message && r.message.length) return;

            // Clone file safely
            return frappe.call({
                method: "frappe.client.insert",
                args: {
                    doc: {
                        doctype: "File",
                        file_name: file_data.file_name,
                        file_url: file_data.file_url,
                        is_private: file_data.is_private || 0,
                        attached_to_doctype: doctype,
                        attached_to_name: docname
                    }
                }
            });
        });
    },

    // ----------------------------------
    // Remove File Everywhere
    // ----------------------------------
    remove_attachment(frm, file_url) {

        frappe.confirm(
            "Remove this attachment from Lead, Survey & Quotation?",
            () => {

                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "File",
                        filters: {
                            file_url: file_url,
                            attached_to_doctype: ["in", ["Lead", "Survey", "Quotation"]]
                        },
                        fields: ["name"],
                        limit_page_length: 0
                    },
                    callback(r) {

                        if (!r.message || !r.message.length) return;

                        Promise.all(
                            r.message.map(f =>
                                frappe.call({
                                    method: "frappe.client.delete",
                                    args: {
                                        doctype: "File",
                                        name: f.name
                                    }
                                })
                            )
                        ).then(() => {
                            frappe.show_alert({
                                message: "Attachment removed everywhere",
                                indicator: "orange"
                            });
                            frm.trigger("render_attachments");
                        });
                    }
                });
            }
        );
    }
});

