                } else {
                    const seen = new Set();

                    r.message.forEach(file => {
                        if (seen.has(file.file_url)) return;
                        seen.add(file.file_url);

                        html += `
                            <div style="margin-bottom:8px; display:flex; align-items:center; gap:8px; padding:6px; background:#f9f9f9; border-radius:4px;">
                                <i class="fa fa-paperclip" style="color:#5e64ff;"></i>
                                <a href="${file.file_url}" target="_blank" style="flex:1; text-decoration:none;">
                                    ${file.file_name}
                                </a>
                                <button
                                    class="btn btn-xs btn-danger remove-attachment"
                                    data-file-url="${file.file_url}">
                                    <i class="fa fa-trash"></i>
                                </button>
                            </div>
                        `;
                    });
                }

                wrapper.html(html);

                // Upload
                wrapper.find(".upload-survey-attachment")
                    .off("click")
                    .on("click", () => frm.trigger("upload_attachment"));

                // Remove (FIXED: call function directly instead of using trigger)
                wrapper.off("click", ".remove-attachment");
                wrapper.on("click", ".remove-attachment", function () {
                    const file_url = $(this).data("file-url");
                    frm.events.remove_attachment(frm, file_url);
                });
            }
        });
    },

    // ----------------------------------
    // Upload & Sync (Survey → Lead → Quotation)
    // ----------------------------------
    upload_attachment(frm) {

        new frappe.ui.FileUploader({
            allow_multiple: true,

            on_success(file_doc) {
                frappe.call({
                    method: "frappe.client.get",
                    args: {
                        doctype: "File",
                        name: file_doc.name
                    },
                    callback(r) {
                        if (!r.message) return;

                        const uploaded = r.message;
                        frm.events.sync_attachment_to_all(frm, uploaded);
                    }
                });
            }
        });
    },

    // ----------------------------------
    // Sync Attachment Everywhere
    // ----------------------------------
    sync_attachment_to_all(frm, file_data) {

        const tasks = [];

        // Lead
        tasks.push(
            frm.events.attach_file_to_doc(
                "Lead",
                frm.doc.lead,
                file_data
            )
        );

        // Quotations linked to Survey
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Quotation",
                filters: { custom_survey: frm.doc.name },
                fields: ["name"]
            },
            callback(r) {

                if (r.message) {
                    r.message.forEach(q => {
                        tasks.push(
                            frm.events.attach_file_to_doc(
                                "Quotation",
                                q.name,
                                file_data
                            )
                        );
                    });
                }

                Promise.all(tasks).then(() => {
                    frappe.show_alert({
                        message: "Attachment synced to Lead & Quotation",
                        indicator: "green"
                    });
                    frm.trigger("render_attachments");
                });
            }
        });
    },

    // ----------------------------------
    // Helper: Attach File
    // ----------------------------------
    attach_file_to_doc(doctype, name, file_data) {
        return frappe.call({
            method: "frappe.client.insert",
            args: {
                doc: {
                    doctype: "File",
                    file_name: file_data.file_name,
                    file_url: file_data.file_url,
                    is_private: file_data.is_private || 0,
                    attached_to_doctype: doctype,
                    attached_to_name: name
                }
            }
        });
    },

    // ----------------------------------
    // Remove Attachment Everywhere
    // ----------------------------------
    remove_attachment(frm, file_url) {

        frappe.confirm(
            "Remove this attachment from Lead & all related Quotations?",
            () => {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "File",
                        filters: { file_url },
                        fields: ["name"]
                    },
                    callback(r) {

                        if (!r.message || !r.message.length) {
                            frappe.show_alert({
                                message: "No files found to remove",
                                indicator: "orange"
                            });
                            return;
                        }

                        Promise.all(
                            r.message.map(f =>
                                frappe.call({
                                    method: "frappe.client.delete",
                                    args: {
                                        doctype: "File",
                                        name: f.name
                                    }
                                })
                            )
                        ).then(() => {
                            frappe.show_alert({
                                message: "Attachment removed everywhere",
                                indicator: "green"
                            });
                            frm.trigger("render_attachments");
                        }).catch((error) => {
                            frappe.msgprint({
                                title: "Error",
                                message: "Failed to remove attachment: " + error.message,
                                indicator: "red"
                            });
                        });
